import{_ as s,C as n,o,c as l,E as r,w as a,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Sweden Healthcare","description":"Healthcare and HRT access for transgender people in Sweden","frontmatter":{"layout":"doc","title":"Sweden Healthcare","description":"Healthcare and HRT access for transgender people in Sweden"},"headers":[],"relativePath":"europe/sweden/healthcare.md","filePath":"europe/sweden/healthcare.md","lastUpdated":null}'),h={name:"europe/sweden/healthcare.md"};function c(p,e,g,u,m,f){const t=n("Badge");return o(),l("div",null,[r(t,{variant:"red"},{default:a(()=>[...e[0]||(e[0]=[i("Gatekeeping Model",-1)])]),_:1}),r(t,{variant:"blue"},{default:a(()=>[...e[1]||(e[1]=[i("Public Healthcare System",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-sweden" tabindex="-1">Healthcare in Sweden <a class="header-anchor" href="#healthcare-in-sweden" aria-label="Permalink to &quot;Healthcare in Sweden&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Sweden operates a gatekeeping model for gender affirming healthcare, centralised through <strong>ANOVA</strong> at Karolinska University Hospital in Stockholm, with regional clinics across the country. This is the most challenging aspect of trans life in Sweden — wait times remain long despite the 2025 legal reforms.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><p>Hormone therapy in Sweden requires:</p><ul><li>Referral to a gender clinic (ANOVA or regional clinic)</li><li>Diagnostic assessment for gender dysphoria (typically 3-12 months of appointments)</li><li>Diagnosis of gender dysphoria usually required</li><li>Endocrinology consult and hormone initiation</li><li>Regular follow-up monitoring</li></ul><p>Wait times:</p><ul><li>Stockholm (ANOVA): 12-24 months for first appointment</li><li>Gothenburg (Ågrenska): 12-24 months</li><li>Lund/Malmö: 12-24 months</li><li>Umeå: 6-12 months (shorter wait, smaller clinic)</li><li>Linköping: 12-18 months</li></ul><h3 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th><th>Languages</th><th>Wait Times</th></tr></thead><tbody><tr><td>ANOVA - Karolinska University Hospital</td><td>Stockholm</td><td>Full spectrum: HRT, surgery, psych</td><td>SV, EN</td><td>12-24 months</td></tr><tr><td>Ågrenska - Sahlgrenska University Hospital</td><td>Gothenburg</td><td>HRT, surgery referrals</td><td>SV, EN</td><td>12-24 months</td></tr><tr><td>Lund University Hospital</td><td>Lund/Malmö</td><td>HRT, surgical referrals</td><td>SV, EN</td><td>12-24 months</td></tr><tr><td>Norrland University Hospital</td><td>Umeå</td><td>HRT, assessments</td><td>SV, EN</td><td>6-12 months</td></tr><tr><td>Linköping University Hospital</td><td>Linköping</td><td>HRT, assessments</td><td>SV, EN</td><td>12-18 months</td></tr></tbody></table><h2 id="private-alternative-options" tabindex="-1">Private/Alternative Options <a class="header-anchor" href="#private-alternative-options" aria-label="Permalink to &quot;Private/Alternative Options&quot;">​</a></h2><p>Private healthcare options are limited in Sweden:</p><ul><li><strong>Private endocrinologists</strong> — Few offer trans care independently; costs €100-200/session</li><li><strong>Gender GP (UK-based)</strong> — Some Swedish patients use this for prescriptions, but Swedish pharmacies may not accept foreign prescriptions easily</li><li><strong>DIY/import</strong> — Some patients import medications, but customs can be strict</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender affirming surgeries are covered by the public healthcare system (Regionen), but wait times are significant:</p><ul><li><strong>Chest/breast surgery (top surgery)</strong> — Covered, wait times 1-2 years</li><li><strong>Genital surgery (bottom surgery)</strong> — Available, wait times 1-3 years</li><li><strong>Facial feminisation surgery</strong> — Very limited public coverage, typically self-funded (€10,000-40,000)</li><li><strong>Hysterectomy/oophorectomy</strong> — Covered</li><li><strong>Voice surgery</strong> — Limited availability</li></ul><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EU member state, Sweden accepts prescriptions from other EU/EEA countries:</p><ul><li>Valid for up to 30 days</li><li>English or Swedish prescriptions recommended</li><li>Swedish doctors may be reluctant to continue prescriptions from non-EU sources</li><li>For ongoing treatment, a Swedish GP or endocrinologist must re-prescribe</li></ul><table tabindex="0"><thead><tr><th>Medication</th><th>Typical Cost (high-cost protection)</th><th>Pharmacy Availability</th></tr></thead><tbody><tr><td>Oestradiol (oral/gel/patches)</td><td>~€5-10/month (after deductible cap)</td><td>Widely available</td></tr><tr><td>Testosterone (gel/injectable)</td><td>~€10-20/month (after deductible cap)</td><td>Widely available</td></tr><tr><td>Cyproterone acetate</td><td>~€8-15/month (after deductible cap)</td><td>Available</td></tr><tr><td>GnRH agonists</td><td>Covered (specialist only)</td><td>Specialist pharmacy</td></tr></tbody></table><p>Sweden&#39;s high-cost protection scheme (högkostnadsskydd) caps prescription medication at ~€240/year.</p><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>ANOVA psych team</strong> — Part of the assessment process</li><li><strong>RFSL</strong> — Peer support groups for trans people</li><li><strong>Transformering.se</strong> — Online resources and referral database</li><li><strong>Private gender therapists</strong> — Limited availability, €80-150/session</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>ANOVA</strong> — <a href="https://www.anova.se/" target="_blank" rel="noreferrer">anova.se</a></li><li><strong>1177 Vårdguiden</strong> — Healthcare guide: <a href="https://www.1177.se/" target="_blank" rel="noreferrer">1177.se</a></li><li><strong>Transformering.se</strong> — Trans health resource: <a href="https://www.transformering.se/" target="_blank" rel="noreferrer">transformering.se</a></li><li><strong>RFSL</strong> — Community support: <a href="https://www.rfsl.se/" target="_blank" rel="noreferrer">rfsl.se</a></li><li><strong>Riksförbundet för transpersoner (RFP)</strong> — Trans advocacy: <a href="https://www.transpersoner.se/" target="_blank" rel="noreferrer">transpersoner.se</a></li></ul>',25))])}const w=s(h,[["render",c]]);export{y as __pageData,w as default};
